const currentUser = <?= json_encode($currentUser, JSON_UNESCAPED_SLASHES) ?>;
const isAdmin = <?= (($currentUser['role'] ?? '') === 'admin') ? 'true' : 'false' ?>;
const siteBuildVersion = 'coastal-hwy1-geometry-be00e94';
const stops = [["0. Medford, OR — fly in / rent car",42.3265,-122.8756,"Arrival / positioning night",["Pick up rental car and supplies.","Drive US-199 toward Crescent City when ready.","Optional: overnight in Medford if arrival is late.","If time allows: Jacksonville historic district or Rogue River area."],["Culture"]],["1. Crescent City",41.7558,-124.2026,"2 nights including arrival night",["California/Oregon border photo stop.","Jedediah Smith Redwoods scenic drive.","Stout Grove redwoods walk if mobility allows.","Battery Point Lighthouse viewpoint; check tide if walking out.","Crescent Beach Overlook and harbor area."],["Redwoods","Viewpoints","Lighthouses","Beaches","Waterfront","Easy walks"]],["1A. Trees of Mystery SkyTrail — Klamath",41.584472,-124.085786,"Redwoods attraction / gondola stop",["Ride the SkyTrail gondola through the redwood canopy.","Located at Trees of Mystery on US-101 near Klamath, between Crescent City and Prairie Creek/Trinidad.","Good fit while based in Crescent City or on the drive south toward Trinidad/Eureka.","Official notes: enclosed six-passenger gondolas; roughly 8–10 minute ride each way.","Verify current hours, weather, and ticket details before going."],["Redwoods","Viewpoints","Family","Easy walks","Tram/Gondola"],{"type":"attraction","icon":"🚡","website":"https://treesofmystery.net/sky-trail/","thumbnail":"https://treesofmystery.net/wp-content/uploads/2020/03/SkyTrail_2MovingRoom.jpg","thumbnailAlt":"Trees of Mystery SkyTrail gondola moving through the redwoods"}],["2. Trinidad / Eureka / Arcata",40.8021,-124.1637,"1 night",["Prairie Creek Redwoods scenic drive.","Newton B. Drury Scenic Parkway.","Big Tree Wayside / easy redwood stops.","Trinidad Head and harbor viewpoints.","Eureka Old Town or Arcata Plaza for dinner."],["Redwoods","Viewpoints","Waterfront"]],["3–4. Mendocino / Fort Bragg",39.4457,-123.8053,"2 nights",["Avenue of the Giants on the drive south.","Leggett to coast section of CA-1.","Mendocino Headlands overlooks.","Point Cabrillo Light Station.","Glass Beach / Fort Bragg coastal trail.","Russian Gulch State Park viewpoints."],["Viewpoints","Beaches","Coast","Hiking"]],["5–6. San Francisco",37.7749,-122.4194,"2 nights",["Arrive via Marin / Golden Gate after the Mendocino coast drive.","Golden Gate Bridge and Marin Headlands viewpoints.","Lands End / Sutro Baths viewpoints.","Presidio or Golden Gate Park.","Ferry Building / Embarcadero.","Alcatraz only if booked in advance and mobility works."],["Viewpoints","Easy walks"]],["7–9. Yosemite area",37.8651,-119.5383,"3 nights",["Tunnel View.","Yosemite Valley: El Capitan Meadow, Cook's Meadow, Valley viewpoints.","Lower Yosemite Fall area if conditions and mobility allow.","Use one full day for Glacier Point and Washburn Point if the road is open.","Use the other full day for Yosemite Valley, Mariposa Grove, or Tioga Road depending on conditions."],["Yosemite","Viewpoints","Easy walks"]],["10. Half Moon Bay or Santa Cruz",37.4636,-122.4286,"1 night",["Return from Yosemite to the coast.","Half Moon Bay harbor and coastal trail.","Pescadero and Pigeon Point Lighthouse area.","Año Nuevo viewpoints if time allows.","Santa Cruz waterfront or Capitola village."],["Yosemite","Viewpoints","Lighthouses","Coast","Waterfront","Hiking"]],["11–13. Monterey / Pacific Grove / Carmel",36.6002,-121.8947,"3 nights",["Monterey Bay Aquarium.","Cannery Row and Old Fisherman's Wharf.","Pacific Grove coastline, Lovers Point, Asilomar.","17-Mile Drive scenic pullouts.","Carmel-by-the-Sea and Carmel Beach overlook.","Point Lobos accessible viewpoints/trails.","Carmel Valley if you want warmer weather or wine tasting."],["Viewpoints","Beaches","Coast","Waterfront","Family","Wine","Hiking"]],["14. Cambria / San Simeon / Morro Bay",35.5641,-121.0808,"1 night",["Big Sur drive southbound.","Bixby Bridge pullout.","Nepenthe / Big Sur village area.","McWay Falls overlook area.","Ragged Point.","Piedras Blancas elephant seal rookery.","Hearst Castle if booked