function popupPadding(){ return window.innerWidth < 860 ? L.point(24, 96) : L.point(28, 72); }
function panPopupFullyIntoView(){
  const popup = document.querySelector('.leaflet-popup');
  if(!popup) return;
  const close = popup.querySelector('.leaflet-popup-close-button');
  const popupRect = popup.getBoundingClientRect();
  const closeRect = close ? close.getBoundingClientRect() : popupRect;
  const rect = {
    left: Math.min(popupRect.left, closeRect.left),
    right: Math.max(popupRect.right, closeRect.right),
    top: Math.min(popupRect.top, closeRect.top),
    bottom: Math.max(popupRect.bottom, closeRect.bottom)
  };
  const pad = window.innerWidth < 860 ? 28 : 14;
  const topPad = window.innerWidth < 860 ? 82 : 54;
  let dx = 0, dy = 0;
  if(rect.left < pad) dx = rect.left - pad;
  else if(rect.right > window.innerWidth - pad) dx = rect.right - (window.innerWidth - pad);
  if(rect.top < topPad) dy = rect.top - topPad;
  else if(rect.bottom > window.innerHeight - pad) dy = rect.bottom - (window.innerHeight - pad);
  if(dx || dy) map.panBy([dx, dy], {animate:true, duration:.2});
}
