let complete=0, errors=0, refreshedSegments=0;
function updateStatus(){
  const totalMiles = mapboxRoutes.reduce((sum,r)=>sum+(r.distance_miles||0),0).toFixed(0);
  const totalHours = mapboxRoutes.reduce((sum,r)=>sum+(r.duration_hours||0),0).toFixed(1);
  const refreshNote = refreshedSegments ? ` ${refreshedSegments} segment(s) refreshed for lodging coordinates.` : '';
  const yosemiteLodging = lodgingLocationForStop(6);
  const yosemiteNote = yosemiteLodging ? ` Yosemite lodging matched: ${yosemiteLodging.title || 'lodging'} (${Number(yosemiteLodging.latitude).toFixed(5)}, ${Number(yosemiteLodging.longitude).toFixed(5)}).` : ' Yosemite lodging not matched.';
  if(errors===0){statusEl.textContent=`Mapbox routes loaded: ${mapboxRoutes.length} segments, about ${totalMiles} miles / ${totalHours} driving hours.${refreshNote}${yosemiteNote} Planning map only; verify closures and navigation before driving.`;}
