function renderPanels(){
  document.getElementById('datesPanel').innerHTML = panelHtml('Trip dates', `<p><b>Fly out / Day 0:</b> ${fmtDate(tripStart)}</p><p><b>Finish:</b> ${fmtDate(addDays(tripStart,18))}</p><p class="auth-note">Dates are shown on every stop card and popup. Apple Maps, Google Maps, and weather links are available per stop.</p>`, true);
  document.getElementById('conditionsPanel').innerHTML = panelHtml('Weather & road links', `<div class="road-links"><a href="https://roads.dot.ca.gov/" target="_blank" rel="noopener">Caltrans road conditions</a><a href="https://quickmap.dot.ca.gov/" target="_blank" rel="noopener">Caltrans QuickMap</a><a href="https://www.nps.gov/yose/planyourvisit/conditions.htm" target="_blank" rel="noopener">Yosemite conditions</a><a href="https://www.nps.gov/redw/planyourvisit/conditions.htm" target="_blank" rel="noopener">Redwoods conditions</a><a href="https://www.bigsurcalifornia.org/highway_conditions.html" target="_blank" rel="noopener">Big Sur Hwy 1</a><a href="https://forecast.weather.gov/" target="_blank" rel="noopener">NOAA weather</a></div>`, false);
  renderReservationsPanel(); renderPhotosPanel(); renderScenicDetails();
}
function reservationStopLabel(r){ const idx = r.stop_id==null||r.stop_id==='' ? null : currentIndexForStopDataId(r.stop_id); return idx===null || !stops[idx] ? 'Unlinked / general trip reservation' : stops[idx][0]; }
function reservationPayloadFromRecord(r){ return {id:r.id||'', stop_id:r.stop_id??'', title:r.title||'', type:r.type||'Other', status:r.status||'planned', reservation_date:r.reservation_date||'', reservation_time:r.reservation_time||'', confirmation:r.confirmation||'', address:r.address||'', latitude:r.latitude||'', longitude:r.longitude||'', phone:r.phone||'', url:r.url||'', cancellation_deadline:r.cancellation_deadline||'', cost:r.cost||'', notes:r.notes||''}; }
function geocodeQueryForReservationPayload(payload){ const title=String(payload.title||'').trim(); const stopLabel=reservationStopLabel(payload).replace(/^\d+[A-Z]?\.\s*/, ''); const address=String(payload.address||'').trim(); if(address) return address; if(/humb.*bay inn/i.test(title)) return '232 W 5th St, Eureka, CA 95501'; if(/beachcomber motel/i.test(title)) return '1111 N Main St, Fort Bragg, CA 95437'; if(/hotel zephyr/i.test(title)) return '250 Beach St, San Francisco, CA 94133'; if(/airbnb/i.test(title)) return ''; return `${title} ${stopLabel} California`; }
async function geocodeReservationPayload(payload){ if(String(payload.type||'').toLowerCase()!=='lodging') return payload; if(numOrNull(payload.latitude)!==null && numOrNull(payload.longitude)!==null) return payload; const query=geocodeQueryForReservationPayload(payload); if(!query) return payload; const url='https://nominatim.openstreetmap.org/search?format=jsonv2&limit=1&q='+encodeURIComponent(query); const results=await fetch(url,{headers:{'Accept':'application/json'}}).then(r=>r.ok?r.json():[]).catch(()=>[]); if(results && results[0] && results[0].lat && results[0].lon){ payload.latitude=results[0].lat; payload.longitude=results[0].lon; if(!payload.address && results[0].display_name) payload.address=results[0].display_name; } return payload; }

function renderReservationsPanel(){ const rows=sortedReservations().map(r=>`<li><b>${esc(r.title)}</b> <span class="tiny">${esc(r.type)} · ${esc(r.status)}</span><br><span class="tiny">Stop: ${esc(reservationStopLabel(r))}</span>${r.reservation_date?`<br>${esc(r.reservation_date)} ${esc(r.reservation_time||'')}`:''}${r.address?`<br><span class="tiny">Address: ${esc(r.address)}</span>`:''}${r.latitude&&r.longitude?`<br><span class="tiny">Location: ${esc(r.latitude)}, ${esc(r.longitude)}</span>`:''}${r.confirmation?`<br><span class="tiny">Confirmation: ${esc(r.confirmation)}</span>`:''}${r.notes?`<br><span>${esc(r.notes)}</span>`:''}${r.url?`<br><a href="${esc(r.url)}" target="_blank" rel="noopener">Reservation link</a>`:''}${tripData.isAdmin?`${String(r.type||'').toLowerCase()==='lodging'?` <button data-edit-reservation-address="${r.id}" type="button">Edit address</button>${(!r.latitude || !r.longitude)?` <button data-geocode-reservation="${r.id}" type="button">Look up location</button>`:''}`:''} <button data-delete-reservation="${r.id}" type="button">Delete</button>`:''}</li>`).join(''); const form=tripData.isAdmin?`<h3>Add reservation</h3><form class="form-grid" id="reservationForm"><select name="stop_id"><option value="">No linked stop</option>${stops.map((s,i)=>`<option value="${stopDataId(i)}">${esc(s[0])}</option>`).join('')}</select><input name="title" placeholder="Reservation title" required><select name="type"><option>Lodging</option><option>Flight</option><option>Rental car</option><option>Activity</option><option>Restaurant</option><option>Park</option><option>Other</option></select><select name="status"><option value="planned">Planned</option><option value="booked">Booked</option><option value="cancelled">Cancelled</option></select><input name="reservation_date" type="date"><input name="reservation_time" type="time"><input name="confirmation" placeholder="Confirmation #"><input name="address" placeholder="Lodging address"><input name="latitude" inputmode="decimal" placeholder="Lodging latitude"><input name="longitude" inputmode="decimal" placeholder="Lodging longitude"><input name="url" placeholder="Link"><textarea name="notes" placeholder="Notes"></textarea><button type="submit">Save reservation</button></form><p class="auth-note">For Lodging reservations, latitude/longitude override the stop marker and app location. Leave blank to keep the original stop location.</p>`:'<p class="auth-note">Admins can add and edit reservations.</p>'; document.getElementById('reservationsPanel').innerHTML=panelHtml('Reservations', `<ul class="mini-list reservation-list">${rows||'<li class="tiny">No reservations entered yet.</li>'}</ul>${form}`, true); }
function renderPhotosPanel(){ const gallery=tripData.settings.smugmug_gallery||''; const count=tripData.photos.length; const form=tripData.isAdmin?`<h3>SmugMug gallery</h3><form class="form-grid" id="galleryForm"><input name="gallery" value="${esc(gallery)}" placeholder="SmugMug trip gallery URL"><button type="submit">Save gallery URL</button></form><button id="syncSmugmug" type="button">Sync GPS photos from gallery</button><h3>Add mapped photo</h3><form class="form-grid" id="photoForm"><input name="title" placeholder="Title"><input name="photo_url" placeholder="SmugMug photo URL"><input name="thumb_url" placeholder="Thumbnail image URL"><input name="latitude" placeholder="Latitude"><input name="longitude" placeholder="Longitude"><button type="submit">Add photo marker</button></form><p class="auth-note">GPS auto-import is prepared for SmugMug metadata; add mapped photos manually here if a photo has no GPS or before API sync is configured.</p>`:`<p class="auth-note">Trip photo markers appear on the map when synced or added by an admin.</p>`; document.getElementById('photosPanel').innerHTML=panelHtml('Trip photos', `<p>${count} mapped photo marker${count===1?'':'s'}.</p>${gallery?`<p><a href="${esc(gallery)}" target="_blank" rel="noopener">Open SmugMug gallery</a></p>`:''}${form}`, false); }
function renderScenicDetails(){ document.getElementById('scenicDetailsContent').innerHTML = `<div class="scenic-card"><h3>Avenue of the Giants</h3><p><b>When:</b> ${stopDate(4)} on the drive to Mendocino / Fort Bragg.</p><ul class="mini-list"><li>Drive the full scenic route north-to-south from Pepperwood / Exit 674 to Phillipsville / Exit 645.</li><li>Allow 60–90 minutes minimum; more with photo stops.</li><li>Recommended stops: Founders Grove, Humboldt Redwoods Visitor Center, Rockefeller Forest, Myers Flat, Miranda, Shrine Drive-Thru Tree.</li></ul><div class="actions"><a href="https://aveofthegiants.com/" target="_blank" rel="noopener">Avenue guide</a><a href="https://www.parks.ca.gov/?page_id=425" target="_blank" rel="noopener">Humboldt Redwoods SP</a><a href="${routeAppleLink(2)}" target="_blank" rel="noopener">Apple Maps route</a></div></div><p class="auth-note">This scenic detail area is separate from the main sidebar panels so more special-route cards can be added later without crowding the itinerary.</p>`; }
function renderPhotoMarkers(){ photoLayer.clearLayers(); const groups=new Map(); tripData.photos.forEach(photo=>{ const lat=Number(photo.latitude), lng=Number(photo.longitude); if(!Number.isFinite(lat)||!Number.isFinite(lng)) return; const key=`${lat.toFixed(6)},${lng.toFixed(6)}`; if(!groups.has(key)) groups.set(key,{lat,lng,photos:[]}); groups.get(key).photos.push(photo); }); groups.forEach(group=>{ const count=group.photos.length; const icon=L.divIcon({className:'photo-icon',html:count>1?`📷<span class="photo-count">${count}</span>`:'📷',iconSize:[count>1?40:32,32],iconAnchor:[16,16],popupAnchor:[0,-18]}); const title=count===1?(group.photos[0].title||'Trip photo'):`${count} trip photos`; const body=group.photos.map((photo,idx)=>`<div class="photo-popup-item">${photo.thumb_url?`<img class="popup-thumb" src="${esc(photo.thumb_url)}" alt="${esc(photo.title||'Trip photo')}" loading="lazy">`:''}<div class="popup-title">${esc(photo.title||`Trip photo ${idx+1}`)}</div>${photo.caption?`<p>${esc(photo.caption)}</p>`:''}${photo.photo_url?`<p><a href="${esc(photo.photo_url)}" target="_blank" rel="noopener">Open in SmugMug</a></p>`:''}</div>`).join(''); L.marker([group.lat,group.lng],{title,icon}).addTo(photoLayer).bindPopup(`<div class="popup-title">${esc(title)}</div>${body}`,{autoPan:true,keepInView:true,autoPanPaddingTopLeft:popupPadding(),autoPanPaddingBottomRight:popupPadding()}); }); }
async function loadTripData({refreshRoutes=false}={}){ try{ const data=await fetch('/auth/api.php?action=bootstrap').then(r=>r.json()); if(data.ok){ tripData=data; applyLodgingStopLocations(); applyLodgingRouteWaypoints(); await renderDrivingRoutes(refreshRoutes, {refreshStaleRoutes:true}); renderPanels(); renderPhotoMarkers(); refreshPopups(); renderItinerary(); } }catch(e){ console.warn('Trip data unavailable', e); renderPanels(); } }
document.addEventListener('submit', async e=>{ if(e.target.matches('.add-item-form')){ e.preventDefault(); const text=e.target.item_text.value.trim(); if(!text) return; await api('add_item',{stop_id:e.target.dataset.stop,item_text:text}); await loadTripData(); markers[Number(e.target.dataset.index)].openPopup(); } if(e.target.id==='reservationForm'){ e.preventDefault(); const payload=await geocodeReservationPayload(Object.fromEntries(new FormData(e.target).entries())); await api('save_reservation',payload); e.target.reset(); await loadTripData({refreshRoutes:true}); } if(e.target.id==='galleryForm'){ e.preventDefault(); await api('save_gallery',Object.fromEntries(new FormData(e.target).entries())); await loadTripData(); } if(e.target.id==='photoForm'){ e.preventDefault(); const payload=Object.fromEntries(new FormData(e.target).entries()); await api('add_photo',payload); e.target.reset(); await loadTripData(); } });
document.addEventListener('click', async e=>{ const delItem=e.target.closest('[data-delete-item]'); if(delItem){ await api('delete_item',{id:delItem.dataset.deleteItem}); await loadTripData(); } const editAddr=e.target.closest('[data-edit-reservation-address]'); if(editAddr){ const reservation=tripData.reservations.find(r=>String(r.id)===String(editAddr.dataset.editReservationAddress)); if(reservation){ const address=prompt('Street address for this lodging reservation:', reservation.address||''); if(address===null) return; const payload=reservationPayloadFromRecord(reservation); payload.address=address.trim(); payload.latitude=''; payload.longitude=''; const res=await api('save_reservation',payload); if(!res.ok){ alert(res.error||'Address save failed'); return; } await loadTripData({refreshRoutes:true}); } } const geoRes=e.target.closest('[data-geocode-reservation]'); if(geoRes){ geoRes.disabled=true; geoRes.textContent='Looking up…'; const res=await api('geocode_reservation',{id:geoRes.dataset.geocodeReservation}); if(!res.ok){ geoRes.disabled=false; geoRes.textContent='Look up location'; alert(res.error||'Location lookup failed'); return; } alert(`Location found and saved.\nQuery: ${res.query}\nCoordinate: ${res.latitude}, ${res.longitude}`); await loadTripData({refreshRoutes:true}); } const delRes=e.target.closest('[data-delete-reservation]'); if(delRes && confirm('Delete this reservation?')){ await api('delete_reservation',{id:delRes.dataset.deleteReservation}); await loadTripData({refreshRoutes:true}); } if(e.target.id==='syncSmugmug'){ const res=await api('sync_smugmug',{}); alert(res.ok ? `Imported ${res.imported||0} GPS photo(s).` : (res.error||'Sync failed')); await loadTripData(); } if(e.target.id==='openScenicDetails'){ document.getElementById('scenicModal').classList.add('open'); document.getElementById('scenicModal').setAttribute('aria-hidden','false'); } if(e.target.id==='closeScenicDetails' || e.target.id==='scenicModal'){ document.getElementById('scenicModal').classList.remove('open'); document.getElementById('scenicModal').setAttribute('aria-hidden','true'); } });
map.fitBounds(routeBounds,{padding:[34,34]}); updateStatus(); renderItinerary(); renderPanels(); loadTripData();
searchEl.addEventListener('input', renderItinerary);
document.getElementById('styleSelect').addEventListener('change', e=>setMapStyle(e.target.value));
document.getElementById('fitRoute').addEventListener('click',()=>map.fitBounds(routeBounds,{padding:[34,34]}));
document.getElementById('printPlan').addEventListener('click',()=>window.print());
document.getElementById('exportPlan').addEventListener('click',()=>{
  const text = stops.map((s,i) => s[0] + '\\nStay: ' + s[3] + '\\nWeather: ' + tempDetail(i) + '\\n- ' + s[4].join('\\n- ') + '\\n').join('\\n');
  const blob = new Blob([text],{type:'text/plain'}); const a=document.createElement('a'); a.href=URL.createObjectURL(blob); a.download='california-trip-itinerary-notes.txt'; a.click(); URL.revokeObjectURL(a.href);
});
document.getElementById('toggleList').addEventListener('click',()=>document.getElementById('sidebar').classList.toggle('collapsed'));
const appShell=document.getElementById('appShell'); const sidebarToggle=document.getElementById('sidebarToggle');
function updateSidebarToggle(){ const collapsed=appShell.classList.contains('sidebar-collapsed'); sidebarToggle.textContent=collapsed?'Show planner':'Hide planner'; sidebarToggle.setAttribute('aria-expanded', collapsed?'false':'true'); setTimeout(()=>map.invalidateSize(),260); }
sidebarToggle.addEventListener('click',()=>{ appShell.classList.toggle('sidebar-collapsed'); updateSidebarToggle(); });
updateSidebarToggle();
document.addEventListener('keydown',e=>{ if(e.key==='Escape'){ map.closePopup(); document.getElementById('scenicModal').classList.remove('open'); document.getElementById('scenicModal').setAttribute('aria-hidden','true'); } });

function isIOSDevice(){ return /iPad|iPhone|iPod/.test(navigator.userAgent) || (navigator.platform === 'MacIntel' && navigator.maxTouchPoints > 1); }
function isStandalonePwa(){ return window.navigator.standalone === true || window.matchMedia('(display-mode: standalone)').matches; }
function setupPwaInstallNotice(){
  const banner=document.getElementById('pwaInstall');
  const dismiss=document.getElementById('dismissPwaInstall');
  if(!banner || !dismiss) return;
  const dismissed=localStorage.getItem('caltrip-pwa-install-dismissed')==='1';
  if(isIOSDevice() && !isStandalonePwa() && !dismissed) banner.classList.add('show');
  dismiss.addEventListener('click',()=>{ localStorage.setItem('caltrip-pwa-install-dismissed','1'); banner.classList.remove('show'); });
}
if('serviceWorker' in navigator){ window.addEventListener('load',()=>{ navigator.serviceWorker.register('/california-trip/sw.js',{scope:'/california-trip/'}).catch(err=>console.warn('PWA service worker registration failed', err)); }); }
setupPwaInstallNotice();
</script>
</body>
</html>